          Identity identityContractor = context.getObjectByName(Identity.class, identityName);
					boolean flag = false;
        	String userType = null;
        	if( null != identityContractor){
          	userType = identityContractor.getAttribute("type");
        	}
        
        	Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");
