      import sailpoint.api.SailPointContext;
      import sailpoint.tools.Util;
      import sailpoint.object.Application;
      import sailpoint.object.Identity;
      import sailpoint.object.Link;
      import sailpoint.object.Custom;
      import sailpoint.object.ProvisioningPlan;
      import sailpoint.object.ProvisioningPlan.AccountRequest;
      import sailpoint.object.ProvisioningPlan.AttributeRequest;
      import sailpoint.object.ProvisioningPlan.Operation;

      Custom customApp = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");

      Identity identity = context.getObjectByName(Identity.class, identityName);

      List listOfAccounts=new ArrayList();
      String appName = "";
      String appType = "";
      String accountName = "";
      String valueCN = null ;
      String disableDN = null;
      String domainAD = null;

      Map domainMap = new HashMap();
      String expireDate= null;
      String inputString = null;
        

      Date date = new Date(); 

      if(plan == null || plan.getAccountRequests() == null || plan.getAccountRequests().size() < 1){
        plan = new ProvisioningPlan();
        if(null!=identity){
          plan.setIdentity(identity); 
        }
      }

      if(null !=identity){       
        if(isContractorLeaverEnable){
          domainAD = identity.getAttribute("domain"); 
        }    
      }

      if(null != date){
        inputString= convertDateToString(date);
      }
      
      String desc = "Immediate Termination by "+launcher+" on "+inputString;
      

      if(null != customApp && null != customApp.get("IgnoreTerminationApplications")){
        listOfAccounts=customApp.get("IgnoreTerminationApplications");
      }

      if(null != identity){         
        List linksAccount= (List) identity.getLinks();
        if (null != listOfAccounts){
          Iterator itrlinksAccount = linksAccount.iterator();
          while (itrlinksAccount.hasNext()) {
            Link account = (Link) itrlinksAccount.next();
            ProvisioningPlan.AccountRequest disableacctReq = new ProvisioningPlan.AccountRequest();
            if(null != account  && null != account.getApplication()){
              appName = account.getApplicationName();
              accountName = account.getNativeIdentity();
              appType = account.getApplication().getType();
			  
			  if (Util.isNotNullOrEmpty(appName) && Util.isNotNullOrEmpty(accountName)){
                if(!(listOfAccounts.contains(appName))){
                  disableacctReq.setApplication(appName);
                  disableacctReq.setNativeIdentity(accountName);
                  disableacctReq.setOperation(ProvisioningPlan.AccountRequest.Operation.Disable);
                  plan.add(disableacctReq);                    
                }  
              }
			  
              if (Util.isNotNullOrEmpty(appType) && appType.equalsIgnoreCase("Active Directory - Direct")){ 

                ProvisioningPlan.AccountRequest acctADReq = new ProvisioningPlan.AccountRequest();        
                if(Util.isNotNullOrEmpty(appName) && Util.isNotNullOrEmpty(accountName)){                    
                  List attReqs = new ArrayList();                 
        					
                  if(Util.isNotNullOrEmpty(leaverType) && leaverType.equalsIgnoreCase("Immediate")){

                    if(null != inputString){
                      expireDate = getADFormatedDateString(inputString);
                    }
										if( !Util.nullSafeCaseInsensitiveEq(identity.getStringAttribute("domain"),"AMITA")){
                    	attReqs.add(new AttributeRequest("description", ProvisioningPlan.Operation.Set, desc));        						
                    	attReqs.add(new AttributeRequest("accountExpires", ProvisioningPlan.Operation.Set, expireDate));
        						}
                  }
                  if(null != attReqs && !attReqs.isEmpty()){       
                    acctADReq.setApplication(appName);
                    acctADReq.setNativeIdentity(accountName);
                    acctADReq.setOperation(ProvisioningPlan.AccountRequest.Operation.Modify);
                    acctADReq.setAttributeRequests(attReqs);
                    plan.add(acctADReq); 
                  }
                } 
              }				
              
            }	
          }
          if(null != itrlinksAccount){
            Util.flushIterator(itrlinksAccount);
          }
        }     	

        AccountRequest iiqAcctReq = new AccountRequest();
        iiqAcctReq.setApplication("IIQ");
        iiqAcctReq.setNativeIdentity(identityName);
        iiqAcctReq.setOperation(AccountRequest.Operation.Modify);
        iiqAcctReq.add(new AttributeRequest("inactive", ProvisioningPlan.Operation.Set, true));
        if(Util.nullSafeCaseInsensitiveEq(identity.getStringAttribute("type"),"non-hr contractor")  && Util.isNotNullOrEmpty(leaverType) && leaverType.equalsIgnoreCase("Immediate") && isContractorLeaverEnable){
          iiqAcctReq.add(new AttributeRequest("ctrexpDt", ProvisioningPlan.Operation.Set, inputString));
        
        
        identity.setAttribute("ctrexpDt",inputString);
        context.startTransaction();
        context.saveObject(identity);
        context.commitTransaction();
		}
       
        
        plan.add(iiqAcctReq);      

        if(null != identity){
          //comment decache //context.decache(identity);
        }
        if(null != customApp ){
          //comment decache //context.decache(customApp);
        }  
      }
        
        

      return plan;

		
        import sailpoint.object.Identity;
        import sailpoint.tools.Util;
          
        Identity contractorIdn = context.getObjectByName(Identity.class, identityName);
      
        if (null != contractorIdn && Util.isNotNullOrEmpty(contractorIdn.getStringAttribute("isContractorManager")) && contractorIdn.getStringAttribute("isContractorManager").equalsIgnoreCase("true")) {          
        	return true;        	
        }
        return false;

		
        import sailpoint.object.Identity;
        import sailpoint.tools.Util;
          
        Identity identityObj = context.getObjectByName(Identity.class, identityName);
      
        if(null != identityObj && !Util.isEmpty(identityObj.getStringAttribute("childPersonaNames")) && Util.nullSafeCaseInsensitiveEq(identityObj.getStringAttribute("manualTerm"),"Yes")){          
        	return true;        	
        }
        return false;

	  
        import sailpoint.object.Filter;
        import sailpoint.object.Identity;
        import sailpoint.object.QueryOptions;
        import sailpoint.object.EmailOptions;
        import sailpoint.object.EmailTemplate;
        import sailpoint.api.ObjectUtil;
        
        int recordCounter = 0; 
        Map managerMap = new HashMap();                    
        QueryOptions queryOptions = new QueryOptions();
        
        Filter managerFilter = Filter.eq("contractorManager", identityName);
        Filter activeFilter = Filter.eq("inactive", false);       
        Filter filter = Filter.and(activeFilter, managerFilter);
        
        queryOptions.addFilter(filter);
        queryOptions.setCloneResults(true);
        Iterator objectList = context.search(Identity.class, queryOptions);
				Identity ownerID = null;
    		if (objectList != null) {
      		while (objectList.hasNext()) {
        		
        		recordCounter++;
        		Identity idObj = objectList.next();  
        		ownerID= idObj.getManager();
        		if(ownerID != null){
        			if( null != idObj && null != managerMap.get(ownerID)){
        				Map temp = managerMap.get(ownerID);      
        				if(null != idObj.getAttribute("samAccountName")){
        					temp.put(idObj.getAttribute("samAccountName"),idObj.getDisplayName());
        				}
        				else{
        					temp.put(idObj.getName(),idObj.getDisplayName());
        				}
        				managerMap.put(ownerID,temp);
        			}
        			else if( null != idObj){
        				Map userData = new HashMap();     
        				if(null != idObj.getAttribute("samAccountName")){
        					userData.put(idObj.getAttribute("samAccountName"),idObj.getDisplayName());
        				}
        				else{
        					userData.put(idObj.getName(),idObj.getDisplayName());
        				}		
        				managerMap.put(ownerID,userData);
       				}
        		}
                    
            if(null != idObj &&  null != identityModel){
              idObj.setAttribute("contractorManager","");
              context.saveObject(idObj);              
              if (0 == (recordCounter % 10)) {
                context.commitTransaction();
            	}       
            }        		         
        	}
        	context.commitTransaction();
         	//comment decache //context.decache();        
        }               
    		Util.flushIterator(objectList);          

        EmailTemplate template = context.getObjectByName(EmailTemplate.class, "Ascension-EmailTemplate-ContractorManager-Change");
        if(null != managerMap && !managerMap.isEmpty()){
          for (Map.Entry entry : managerMap.entrySet()) {              
            EmailOptions options = new EmailOptions();
            Map args = new HashMap();
            if(null != entry){
              args.put("userMap",entry.getValue());
              if(null != entry.getKey() && null != entry.getKey().getDisplayName()){
                args.put("ownerName",entry.getKey().getDisplayName()); 
        				args.put("identityDisplayName",identityDisplayName); 
                options.setTo(entry.getKey().getAttribute("email"));
              }
              options.setVariables(args);

              if(null != options && template !=null){
                context.sendEmailNotification(template,options); 
              }
            }
          } 
          if(template !=null){
            //comment decache //context.decache(template);
          }
        }

		
        import sailpoint.object.Identity;
        import sailpoint.tools.Util;
          
        Identity identityObj = context.getObjectByName(Identity.class, identityName);
      
        if(null != identityObj && !Util.isEmpty(identityObj.getStringAttribute("childPersonaNames")) && Util.nullSafeCaseInsensitiveEq(identityObj.getStringAttribute("manualTerm"),"Yes")){          
        	return true;        	
        }
        return false;

        import sailpoint.object.Identity;
        import sailpoint.tools.Util;
        import sailpoint.object.ProvisioningPlan;
        import sailpoint.object.ProvisioningPlan.AccountRequest;
        import sailpoint.object.ProvisioningPlan.AttributeRequest;
        import sailpoint.api.Provisioner;
        
        Identity identityObj = context.getObjectByName(Identity.class, identityName);
        ArrayList childPersonas = identityObj.getAttribute("childPersonaNames"); 
        String inputString = "";
        

      	Date date = new Date(); 
        if(null != date){
        	inputString= convertDateToString(date);
      	}
        
        if(childPersonas!=null && !childPersonas.isEmpty())
        {
		  Provisioner provisioner= new Provisioner(context);
          provisioner.setNoLocking(true);
          provisioner.setOptimisticProvisioning(true);
		  
          for(String childPersona: childPersonas)
        	{
        
            Identity childID = context.getObjectByName(Identity.class, childPersona);
            if(null != childID){       		
        				ProvisioningPlan plan = new ProvisioningPlan();
                AccountRequest iiqAcctReq = new AccountRequest();
                iiqAcctReq.setApplication("IIQ");
                iiqAcctReq.setNativeIdentity(childPersona);
                iiqAcctReq.setOperation(AccountRequest.Operation.Modify);                     	       				    
                iiqAcctReq.add(new AttributeRequest("manualTerm", ProvisioningPlan.Operation.Set, "Yes"));
        				iiqAcctReq.add(new AttributeRequest("inactive", ProvisioningPlan.Operation.Set, true));
                if(Util.nullSafeCaseInsensitiveEq(childID.getStringAttribute("type"),"non-hr contractor")){
                  iiqAcctReq.add(new AttributeRequest("ctrexpDt", ProvisioningPlan.Operation.Set, inputString));
                }
                plan.add(iiqAcctReq);
                plan.setIdentity(childID);

                if(null != plan && !plan.isEmpty()){
                  
                  provisioner.execute(plan);
                }
              }
            }
          }
